customEChartConfig:
{{ ((chartType) => ( 
(() => {
  const raw = Renewal_List.filteredTableData || Renewal_List.tableData || [];
  const data = raw
    .filter(r => r.contract_expired_date)
    .reduce((acc, r) => {
      const date = r.contract_expired_date;
      // Status bestimmen; leere/fehlende Werte werden zu "No Status"
      const rawStatus = (r.Status ?? '').toString().trim();
      const status = rawStatus ? rawStatus : 'No Status';
      if (!acc[date]) acc[date] = {};
      acc[date][status] = (acc[date][status] || 0) + 1; // Hier war der Fehler
      return acc;
    }, {});

  const dates = Object.keys(data).sort();
  const statuses = [...new Set(Object.values(data).flatMap(Object.keys))];

   // Color Coding inkl. Hellgrau für "No Status"
  const colors = {
    'At Risk': '#ea4335',      // Rot
    'Low Risk': '#AEEA00',     // Lime (hellgrünlich)
    'Closed Won': '#22b31e',   // Dunkelgrün
    'Renewal Lost': '#424242', // Dunkelgrau
    'No Status': '#CCCCCC'     // Hellgrau, gut sichtbar auf weiß
  };

  return {
    tooltip: { trigger: 'axis', axisPointer: { type: 'shadow' } },
    legend: { data: statuses },
    grid: { left: '3%', right: '4%', bottom: '3%', containLabel: true },
    xAxis: {
      type: 'category',
      data: dates,
      axisLabel: {
        formatter: value => new Date(value).toLocaleDateString('de-DE'),
        rotate: 45
      }
    },
    yAxis: { type: 'value' },
    series: statuses.map(status => ({
      name: status,
      type: 'bar',
      stack: 'total',
      emphasis: { focus: 'series' },
      itemStyle: { color: colors[status] || '#CCCCCC' }, // Fallback: Hellgrau
      data: dates.map(date => (data[date]?.[status] ?? 0))
    }))
  };
})()
))(RiskTimelineChart.chartType) }}
